import{G as o}from"./chunks/shared-links.CZ5QUsOH.js";import{C as a,o as s,c as r,j as t,a as n,E as l,k as c,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md"}'),h={name:"introduction.md"},b=Object.assign(h,{setup(p){return(u,e)=>{const i=a("YoutubePlayer");return s(),r("div",null,[e[0]||(e[0]=t("h1",{id:"introduction",tabindex:"-1"},[t("i",{class:"ph ph-hand-waving"}),n(" Introduction "),t("a",{class:"header-anchor",href:"#introduction","aria-label":'Permalink to "<i class="ph ph-hand-waving"></i> Introduction"'},"​")],-1)),l(i,{src:c(o).youtubeVideo},null,8,["src"]),e[1]||(e[1]=d('<p><strong>Web Adaptive Performance (WebAP)</strong> is a tool for the dynamic optimization of Unity WebGL applications.</p><p>It helps strike the perfect balance between visual quality and stable FPS across different devices: from powerful PCs to weak smartphones. Instead of rigid limits, the plugin analyzes frame timings in real-time. It detects the root cause of performance drops, smoothly reduces the load until stabilization is achieved, and restores quality when Performance Headroom becomes available.</p><div class="tip custom-block"><p class="custom-block-title">Device Adaptation</p><p>Set your Unity project to maximum quality settings by default. The plugin will automatically scale them down at runtime if the current device cannot handle the load.</p></div><h2 id="why-webap" tabindex="-1">Why WebAP? <a class="header-anchor" href="#why-webap" aria-label="Permalink to &quot;Why WebAP?&quot;">​</a></h2><p><strong><i class="ph-bold ph-x"></i> Why not the official Adaptive Performance package?</strong><br> The official Unity package is a powerful tool, but it is fundamentally incompatible with WebGL. It relies on two types of providers, and both hit browser limitations:</p><ol><li><strong>Native Providers (Android):</strong> Rely on system APIs to retrieve thermal status (Thermal Headroom) and manage frequencies. The browser sandbox blocks any hardware access, making this approach impossible. Emerging web standards (like the <em>Compute Pressure API</em>) only monitor the CPU and fail to provide precise data for 3D graphics.</li><li><strong>Basic Provider:</strong> Unity&#39;s cross-platform mathematical provider. It relies on <code>FrameTimingManager</code>. However, for it to function, the engine requires high-precision hardware GPU timers, which are forcibly blocked or heavily obfuscated in browsers for security reasons (protection against <em>Spectre/Meltdown</em> attacks). Consequently, the official Basic Provider physically fails to initialize in WebGL.</li></ol><p><strong><i class="ph-bold ph-check"></i> The WebAP Solution:</strong> We have engineered an architecture tailored exclusively for the specifics of the web. WebAP also utilizes <code>FrameTimingManager</code>, but instead of a strict dependency on blocked GPU timers, the plugin employs secure heuristic analysis. It bypasses browser anomalies (such as metric distortion caused by <code>setTimeout</code> in Emscripten) and uses pure mathematics to calculate bottlenecks (CPU vs GPU). This provides an AAA-level optimization system that operates legally and stably in any browser.</p><p><strong><i class="ph-bold ph-x"></i> Why not standard scaling scripts?</strong><br> Classic solutions simply reduce screen resolution during any lag. This is useless if the application stutters due to CPU calculations (physics, scripts, logic) rather than rendering.</p><p><strong><i class="ph-fill ph-check-fat"></i> How WebAP Works:</strong></p><ul><li><i class="ph-fill ph-brain"></i> <strong>Bottleneck Detection</strong><br> The plugin mathematically determines what limits the frame: CPU or GPU. If physics lags, the system simplifies physics without reducing screen resolution. Over 12 independent Scalers (Shadows, LOD, Layer Culling, etc.) are provided for this purpose.</li><li><i class="ph-fill ph-hand-palm"></i> <strong>Anti Yo-Yo Penalty System</strong><br> Solves the frequent issue of dynamic resolution where Quality flickering occurs. If improving graphics immediately causes an FPS drop, the system temporarily enforces a Penalty Lockout to block further increases.</li><li><i class="ph-fill ph-layout"></i> <strong>Preserving UI Clarity</strong><br> If you choose the scaling mode via <code>RenderTexture</code>, the resolution of the 3D world decreases, but the interface remains in the Native Browser Scaling resolution. A custom <code>WebScaledPhysicsRaycaster</code> component automatically recalculates ray coordinates so that clicks on 3D objects function correctly regardless of frame compression.</li><li><i class="ph-fill ph-lightning"></i> <strong>Zero-GC Architecture</strong><br> The entire project is designed with strict memory economy. The core uses O(1) ring buffers and performs zero allocations in the <code>Update</code> loop. Therefore, the plugin does not trigger the Garbage Collector (GC).</li><li><i class="ph-fill ph-broom"></i> <strong>Zero Build Bloat</strong><br> Many assets bloat the release build by placing their prefabs and textures in the <code>Resources</code> folder (forcing the engine to include them in the build). WebAP&#39;s architecture avoids this error. All tooling and the Dashboard UI are automatically stripped during compilation unless explicitly added to a scene. Only the lightweight core enters the final project.</li><li><i class="ph-fill ph-gear"></i> <strong>Plug-and-Play Integration</strong><br> Settings are consolidated in a unified interface within <em>Project Settings</em>. The plugin automatically injects into the build — you do not need to manually place manager prefabs on scenes.</li></ul><h2 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h2><ul><li><strong>Unity Version:</strong> <code>2020.3 LTS</code> and higher. The plugin utilizes modern APIs and automatically adopts new engine features (e.g., <code>Mesh LOD Threshold</code> support for Unity 6000.2+).</li><li><strong>Render Pipelines:</strong> Seamless support for both Built-in Render Pipeline (BiRP) and Universal Render Pipeline (URP).</li></ul>',12))])}}});export{f as __pageData,b as default};
